output_path = "speculative_decoding/prompts/hindi_prompts.jsonl"
with open(output_path, "w", encoding="utf-8") as f:
    for prompt in prompts:
        f.write(json.dumps({"text": prompt}, ensure_ascii=False) + "\n")

print(f"Saved {len(prompts)} prompts to {output_path}")

with open(output_path, "r", encoding="utf-8") as f:
    lines = f.readlines()

print(f"Verified: {len(lines)} lines in file")
print(f"\nSample entries:")
for i in [0, 50, 120]:
    record = json.loads(lines[i])
    print(f"  [{i}] {record['text'][:60]}...")